var surah052 = {
  number: 52,
  nameArabic: "At-Tur",
  nameEnglish: "At-Tur",
  meaning: "The Mount",
  totalAyahs: 49,
  ayahs: [
    { number: 1, arabic: "وَٱلطُّورِ", transliteration: "Waalttoori", transliterationB: "Wat-Toor", english: "By the Mount (of Revelation)", romanUrdu: "Kasam hai Tur (Mount) ki" },
    { number: 2, arabic: "وَكِتَٰبٍۢ مَّسْطُورٍۢ", transliteration: "Wakitabin mastoorin", transliterationB: "Wa kitaabim mastoor", english: "By a Decree inscribed", romanUrdu: "Aur ek aisi khuli kitaab ki" },
    { number: 3, arabic: "فِى رَقٍّۢ مَّنشُورٍۢ", transliteration: "Fee raqqin manshoorin", transliterationB: "Fee raqqim manshoor", english: "In a Scroll unfolded", romanUrdu: "Jo raqeeq jild(fine parchment) mein likkhi hui hai" },
    { number: 4, arabic: "وَٱلْبَيْتِ ٱلْمَعْمُورِ", transliteration: "Waalbayti almaAAmoori", transliterationB: "Wal baitil ma'moor", english: "By the much-frequented Fane", romanUrdu: "Aur aabaad (much-frequented) ghar ki" },
    { number: 5, arabic: "وَٱلسَّقْفِ ٱلْمَرْفُوعِ", transliteration: "Waalssaqfi almarfooAAi", transliterationB: "Wassaqfil marfoo", english: "By the Canopy Raised High", romanUrdu: "Aur unchi chatt (canopy) ki" },
    { number: 6, arabic: "وَٱلْبَحْرِ ٱلْمَسْجُورِ", transliteration: "Waalbahri almasjoori", transliterationB: "Wal bahril masjoor", english: "And by the Ocean filled with Swell", romanUrdu: "Aur maujzan samandar (swelling sea) ki" },
    { number: 7, arabic: "إِنَّ عَذَابَ رَبِّكَ لَوَٰقِعٌۭ", transliteration: "Inna AAathaba rabbika lawaqiAAun", transliterationB: "Inna 'azaaba Rabbika lawaaqi", english: "Verily, the Doom of thy Lord will indeed come to pass", romanUrdu: "Ke tere Rubb ka azaab zaroor waqeh honay wala hai" },
    { number: 8, arabic: "مَّا لَهُۥ مِن دَافِعٍۢ", transliteration: "Ma lahu min dafiAAin", transliterationB: "Maa lahoo min daafi", english: "There is none can avert it", romanUrdu: "Jisey koi dafa karne wala nahin" },
    { number: 9, arabic: "يَوْمَ تَمُورُ ٱلسَّمَآءُ مَوْرًۭا", transliteration: "Yawma tamooru alssamao mawran", transliterationB: "Yawma tamoorus samaaa'u mawraa", english: "On the Day when the firmament will be in dreadful commotion", romanUrdu: "Woh us roz waqeh hoga jab aasmaan buri tarah dagmagayega" },
    { number: 10, arabic: "وَتَسِيرُ ٱلْجِبَالُ سَيْرًۭا", transliteration: "Wataseeru aljibalu sayran", transliterationB: "Wa taseerul jibaalu sairaa", english: "And the mountains will fly hither and thither", romanUrdu: "Aur pahad udey udey phirenge" },
    { number: 11, arabic: "فَوَيْلٌۭ يَوْمَئِذٍۢ لِّلْمُكَذِّبِينَ", transliteration: "Fawaylun yawmaithin lilmukaththibeena", transliterationB: "Fawailuny yawma 'izil lil mukaazzibeen", english: "Then woe that Day to those that treat (Truth) as Falsehood", romanUrdu: "Tabahi hai us roz un jhutlane walon ke liye" },
    { number: 12, arabic: "ٱلَّذِينَ هُمْ فِى خَوْضٍۢ يَلْعَبُونَ", transliteration: "Allatheena hum fee khawdin yalAAaboona", transliterationB: "Allazeena hum fee khawdiny yal'aboon", english: "That play (and paddle) in shallow trifles", romanUrdu: "Jo aaj khel ke taur par apni hujjat baaziyon mein lagey huey hain" },
    { number: 13, arabic: "يَوْمَ يُدَعُّونَ إِلَىٰ نَارِ جَهَنَّمَ دَعًّا", transliteration: "Yawma yudaAAAAoona ila nari jahannama daAAAAan", transliterationB: "Yawma yuda'-'oona ilaa naari jahannama da'-'aa", english: "That Day shall they be thrust down to the Fire of Hell, irresistibly", romanUrdu: "Jis din unhein dhakke maar maar kar naar-e-jahannum (fire of hell) ki taraf le chala jayega" },
    { number: 14, arabic: "هَٰذِهِ ٱلنَّارُ ٱلَّتِى كُنتُم بِهَا تُكَذِّبُونَ", transliteration: "Hathihi alnnaru allatee kuntum biha tukaththiboona", transliterationB: "Haazihin naarul latee kuntum bihaa tukazziboon", english: "This:, it will be said, \"Is the Fire,- which ye were wont to deny", romanUrdu: "Us waqt unse kaha jayega ke “ yeh wahi aag hai jisey tum jhutlaya karte thay" },
    { number: 15, arabic: "أَفَسِحْرٌ هَٰذَآ أَمْ أَنتُمْ لَا تُبْصِرُونَ", transliteration: "Afasihrun hatha am antum la tubsiroona", transliterationB: "Afasihrun haazaaaa am antum laa tubsiroon", english: "Is this then a fake, or is it ye that do not see", romanUrdu: "Ab batao yeh jaadu hai ya tumhein soojh nahin raha hai" },
    { number: 16, arabic: "ٱصْلَوْهَا فَٱصْبِرُوٓا۟ أَوْ لَا تَصْبِرُوا۟ سَوَآءٌ عَلَيْكُمْ ۖ إِنَّمَا تُجْزَوْنَ مَا كُنتُمْ تَعْمَلُونَ", transliteration: "Islawha faisbiroo aw la tasbiroo sawaon AAalaykum innama tujzawna ma kuntum taAAmaloona", transliterationB: "Islawhaa fasbirooo aw laa tasbiroo sawaaa'un 'alaikum innamaa tujzawna maa kuntum ta'maloon", english: "Burn ye therein: the same is it to you whether ye bear it with patience, or not: Ye but receive the recompense of your (own) deeds", romanUrdu: "Jao ab jhulso iske andar, tum khwa sabr karo ya na karo, tumhare liye yaksan hai, tumhein waisa hi badla diya ja raha hai jaise tum amal kar rahey thay" },
    { number: 17, arabic: "إِنَّ ٱلْمُتَّقِينَ فِى جَنَّٰتٍۢ وَنَعِيمٍۢ", transliteration: "Inna almuttaqeena fee jannatin wanaAAeemin", transliterationB: "Innal muttaqeena fee jannaatinw wa na'eem", english: "As to the Righteous, they will be in Gardens, and in Happiness", romanUrdu: "Muttaqi log wahan baagon (gardens) aur niyamaton mein hongey" },
    { number: 18, arabic: "فَٰكِهِينَ بِمَآ ءَاتَىٰهُمْ رَبُّهُمْ وَوَقَىٰهُمْ رَبُّهُمْ عَذَابَ ٱلْجَحِيمِ", transliteration: "Fakiheena bima atahum rabbuhum wawaqahum rabbuhum AAathaba aljaheemi", transliterationB: "Faakiheena bimaaa aataahum rabbuhum wa waqaahum rabbuhum 'azaabal jaheem", english: "Enjoying the (Bliss) which their Lord hath bestowed on them, and their Lord shall deliver them from the Penalty of the Fire", romanUrdu: "Lutf le rahe hongey un cheezon se jo unka Rubb unhein dega, aur unka Rubb unhein dozakh ke azaab se bacha lega" },
    { number: 19, arabic: "كُلُوا۟ وَٱشْرَبُوا۟ هَنِيٓـًٔۢا بِمَا كُنتُمْ تَعْمَلُونَ", transliteration: "Kuloo waishraboo haneean bima kuntum taAAmaloona", transliterationB: "Kuloo washraboo haneee 'am bimaa kuntum ta'maloon", english: "(To them will be said:) \"Eat and drink ye, with profit and health, because of your (good) deeds", romanUrdu: "(Unse kaha jayega) khao aur peo mazey se apne un aamaal ke siley mein jo tum karte rahey ho" },
    { number: 20, arabic: "مُتَّكِـِٔينَ عَلَىٰ سُرُرٍۢ مَّصْفُوفَةٍۢ ۖ وَزَوَّجْنَٰهُم بِحُورٍ عِينٍۢ", transliteration: "Muttakieena AAala sururin masfoofatin wazawwajnahum bihoorin AAeenin", transliterationB: "Muttaki'eena 'alaa sururim masfoofatinw wa zawwaj naahum bihoorin 'een", english: "They will recline (with ease) on Thrones (of dignity) arranged in ranks; and We shall join them to Companions, with beautiful big and lustrous eyes", romanUrdu: "Woh aamne saamne bichey huey takhaton(thrones) par takiye(couches) lagaye baithey hongey aur hum khoobsurat aankhon waali hoorein unse biyah (marry) denge" },
    { number: 21, arabic: "وَٱلَّذِينَ ءَامَنُوا۟ وَٱتَّبَعَتْهُمْ ذُرِّيَّتُهُم بِإِيمَٰنٍ أَلْحَقْنَا بِهِمْ ذُرِّيَّتَهُمْ وَمَآ أَلَتْنَٰهُم مِّنْ عَمَلِهِم مِّن شَىْءٍۢ ۚ كُلُّ ٱمْرِئٍۭ بِمَا كَسَبَ رَهِينٌۭ", transliteration: "Waallatheena amanoo waittabaAAathum thurriyyatuhum bieemanin alhaqna bihim thurriyyatahum wama alatnahum min AAamalihim min shayin kullu imriin bima kasaba raheenun", transliterationB: "Wallazeena aamanoo wattaba'at hum zurriyyatuhum bieemaanin alhaqnaa bihim zurriyyatahum wa maaa alatnaahum min 'amalihim min shai'; kullum ri'im bimaa kasaba raheen", english: "And those who believe and whose families follow them in Faith,- to them shall We join their families: Nor shall We deprive them (of the fruit) of aught of their works: (Yet) is each individual in pledge for his deeds", romanUrdu: "Jo log imaan laaye hain aur unki aulad bhi kisi darja-e-imaan mein unke naksh-e-qadam par chali hai unki us aulad ko bhi hun (jannat mein) unke saath mila denge aur unke amaal mein koi ghaata(loss) unko na denge. Har shaks apne kasb ke aevaz rehan hai.( Every person is pledged to what he did)" },
    { number: 22, arabic: "وَأَمْدَدْنَٰهُم بِفَٰكِهَةٍۢ وَلَحْمٍۢ مِّمَّا يَشْتَهُونَ", transliteration: "Waamdadnahum bifakihatin walahmin mimma yashtahoona", transliterationB: "Wa amdadnaahum bifaa kihatinw wa lahmim mimmaa yashtahoon", english: "And We shall bestow on them, of fruit and meat, anything they shall desire", romanUrdu: "Hum unko har tarah ke phal (fruits) aur gosht , jis cheez ko bhi unka ji chahega khoob diye chale jayenge" },
    { number: 23, arabic: "يَتَنَٰزَعُونَ فِيهَا كَأْسًۭا لَّا لَغْوٌۭ فِيهَا وَلَا تَأْثِيمٌۭ", transliteration: "YatanazaAAoona feeha kasan la laghwun feeha wala tatheemun", transliterationB: "Yatanaaza'oona feehaa kaasal laa laghwun feehaa wa laa taaseem", english: "They shall there exchange, one with another, a (loving) cup free of frivolity, free of all taint of ill", romanUrdu: "Wahan woh ek dusre se jaam-e-sharaab lapak lapak kar le rahey hongey jis mein na yawa-goyi (ill speech) hogi na bad-kirdari" },
    { number: 24, arabic: "۞ وَيَطُوفُ عَلَيْهِمْ غِلْمَانٌۭ لَّهُمْ كَأَنَّهُمْ لُؤْلُؤٌۭ مَّكْنُونٌۭ", transliteration: "Wayatoofu AAalayhim ghilmanun lahum kaannahum luluon maknoonun", transliterationB: "Wa yatoofu 'alaihim ghilmaanul lahum ka annahum lu'lu'um maknoon", english: "Round about them will serve, (devoted) to them, young male servants (handsome) as Pearls well-guarded", romanUrdu: "Aur unki khidmat mein woh ladke daudte (running) phir rahey hongey jo unhi ke liye makhsoos hongey, aisey khoobsurat jaise chupa kar rakkhe huey moti(pearls)" },
    { number: 25, arabic: "وَأَقْبَلَ بَعْضُهُمْ عَلَىٰ بَعْضٍۢ يَتَسَآءَلُونَ", transliteration: "Waaqbala baAAduhum AAala baAAdin yatasaaloona", transliterationB: "Wa aqbala ba'duhum 'alaa ba'diny yatasaaa'aloon", english: "They will advance to each other, engaging in mutual enquiry", romanUrdu: "Yeh log apas mein ek dusre se (duniya mein guzre huey) halaat puchenge" },
    { number: 26, arabic: "قَالُوٓا۟ إِنَّا كُنَّا قَبْلُ فِىٓ أَهْلِنَا مُشْفِقِينَ", transliteration: "Qaloo inna kunna qablu fee ahlina mushfiqeena", transliterationB: "Qaalooo innaa kunnaa qablu feee ahlinaa mushfiqeen", english: "They will say: \"Aforetime, we were not without fear for the sake of our people", romanUrdu: "Yeh kahenge ke hum pehle apne ghar waalon mein darte huey zindagi basar karte thay" },
    { number: 27, arabic: "فَمَنَّ ٱللَّهُ عَلَيْنَا وَوَقَىٰنَا عَذَابَ ٱلسَّمُومِ", transliteration: "Famanna Allahu AAalayna wawaqana AAathaba alssamoomi", transliterationB: "Famannnal laahu 'alainaa wa waqaanaa 'azaabas samoom", english: "But Allah has been good to us, and has delivered us from the Penalty of the Scorching Wind", romanUrdu: "Aakhir e kaar Allah ne hum par fazl farmaya aur humein jhulsa dene wali hawa ke azaab se bacha liya" },
    { number: 28, arabic: "إِنَّا كُنَّا مِن قَبْلُ نَدْعُوهُ ۖ إِنَّهُۥ هُوَ ٱلْبَرُّ ٱلرَّحِيمُ", transliteration: "Inna kunna min qablu nadAAoohu innahu huwa albarru alrraheemu", transliterationB: "Innaa kunnaa min qablu nad'oohu innahoo huwal barrur raheem", english: "Truly, we did call unto Him from of old: truly it is He, the Beneficent, the Merciful", romanUrdu: "Hum pichli zindagi mein usi se duaein maangte thay, woh waqai bada hi Mohsin (beneficent) aur Raheem hai" },
    { number: 29, arabic: "فَذَكِّرْ فَمَآ أَنتَ بِنِعْمَتِ رَبِّكَ بِكَاهِنٍۢ وَلَا مَجْنُونٍ", transliteration: "Fathakkir fama anta biniAAmati rabbika bikahin wala majnoonin", transliterationB: "Fazakkir famaaa anta bini'mati rabbika bikaahininw wa laa majnoon", english: "Therefore proclaim thou the praises (of thy Lord): for by the Grace of thy Lord, thou art no (vulgar) soothsayer, nor art thou one possessed", romanUrdu: "Pas aey nabi, tum nasihat kiye jao, apne Rubb ke fazal se na tum kaahin (soothsayer) ho aur na majnoon (madman)" },
    { number: 30, arabic: "أَمْ يَقُولُونَ شَاعِرٌۭ نَّتَرَبَّصُ بِهِۦ رَيْبَ ٱلْمَنُونِ", transliteration: "Am yaqooloona shaAAirun natarabbasu bihi rayba almanooni", transliterationB: "Am yaqooloona shaa'irun natarabbasu bihee raibal manoon", english: "Or do they say:- \"A Poet! we await for him some calamity (hatched) by Time", romanUrdu: "Kya yeh log kehte hain ke yeh shaks shayar hai jiske haqq mein hum gardish-e-ayyam (misfortune) ke intizaar kar rahe hain" },
    { number: 31, arabic: "قُلْ تَرَبَّصُوا۟ فَإِنِّى مَعَكُم مِّنَ ٱلْمُتَرَبِّصِينَ", transliteration: "Qul tarabbasoo fainnee maAAakum mina almutarabbiseena", transliterationB: "Qul tarabbasoo fa innee ma'akum minal mutarabbiseen", english: "Say thou: \"Await ye!- I too will wait along with you", romanUrdu: "Inse kaho, accha intizaar karo, main bhi tumhare saath intizaar karta hoon" },
    { number: 32, arabic: "أَمْ تَأْمُرُهُمْ أَحْلَٰمُهُم بِهَٰذَآ ۚ أَمْ هُمْ قَوْمٌۭ طَاغُونَ", transliteration: "Am tamuruhum ahlamuhum bihatha am hum qawmun taghoona", transliterationB: "Am taamuruhum ahlaamuhum bihaazaaa am hum qawmun taaghoon", english: "Is it that their faculties of understanding urge them to this, or are they but a people transgressing beyond bounds", romanUrdu: "Kya inki aqalein(minds) inhein aisi hi baatein karne ke liye kehti hain? Ya dar-haqeeqat yeh inaad (transgression)mein hadd se guzare huey log hain" },
    { number: 33, arabic: "أَمْ يَقُولُونَ تَقَوَّلَهُۥ ۚ بَل لَّا يُؤْمِنُونَ", transliteration: "Am yaqooloona taqawwalahu bal la yuminoona", transliterationB: "Am yaqooloona taqawwalah; bal laa yu'minoon", english: "Or do they say, \"He fabricated the (Message)\"? Nay, they have no faith", romanUrdu: "Kya ye kehte hain ke is shaks ne yeh quraan khud ghad (invented/fabricated) liya hai? Asal baat yeh hai ke yeh imaan nahin lana chahte" },
    { number: 34, arabic: "فَلْيَأْتُوا۟ بِحَدِيثٍۢ مِّثْلِهِۦٓ إِن كَانُوا۟ صَٰدِقِينَ", transliteration: "Falyatoo bihadeethin mithlihi in kanoo sadiqeena", transliterationB: "Falyaatoo bihadeesim misliheee in kaanoo saadiqeen", english: "Let them then produce a recital like unto it,- If (it be) they speak the truth", romanUrdu: "Agar yeh apne is qaul (saying) mein sacche hain to isi shaan ka ek kalaam bana layein" },
    { number: 35, arabic: "أَمْ خُلِقُوا۟ مِنْ غَيْرِ شَىْءٍ أَمْ هُمُ ٱلْخَٰلِقُونَ", transliteration: "Am khuliqoo min ghayri shayin am humu alkhaliqoona", transliterationB: "Am khuliqoo min ghairi shai'in am humul khaaliqoon", english: "Were they created of nothing, or were they themselves the creators", romanUrdu: "Kya yeh kisi khaliq ke bagair khud paida ho gaye hain? Ya yeh khud apne khaliq hain" },
    { number: 36, arabic: "أَمْ خَلَقُوا۟ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ ۚ بَل لَّا يُوقِنُونَ", transliteration: "Am khalaqoo alssamawati waalarda bal la yooqinoona", transliterationB: "Am khalaqus samaawaati wal ard; bal laa yooqinoon", english: "Or did they create the heavens and the earth? Nay, they have no firm belief", romanUrdu: "Ya zameen aur aasmaano ko inhon ne paida kiya hai? Asal baat yeh hai ke yeh yaqeen nahin rakhte" },
    { number: 37, arabic: "أَمْ عِندَهُمْ خَزَآئِنُ رَبِّكَ أَمْ هُمُ ٱلْمُصَۣيْطِرُونَ", transliteration: "Am AAindahum khazainu rabbika am humu almusaytiroona", transliterationB: "Am'indahum khazaaa'inu rabbika am humul musaitiroon", english: "Or are the Treasures of thy Lord with them, or are they the managers (of affairs)", romanUrdu: "Kya tere Rubb ke khazane in ke kabze mein hain? Ya un par inhi ka hukum chalta hai" },
    { number: 38, arabic: "أَمْ لَهُمْ سُلَّمٌۭ يَسْتَمِعُونَ فِيهِ ۖ فَلْيَأْتِ مُسْتَمِعُهُم بِسُلْطَٰنٍۢ مُّبِينٍ", transliteration: "Am lahum sullamun yastamiAAoona feehi falyati mustamiAAuhum bisultanin mubeenin", transliterationB: "Am lahum sullamuny yastami'oona feehi falyaati mustami'uhum bisultaanim mubeen", english: "Or have they a ladder, by which they can (climb up to heaven and) listen (to its secrets)? Then let (such a) listener of theirs produce a manifest proof", romanUrdu: "Kya inke paas koi seedi(ladder) hai jispar chadh kar yeh ilm-e-baala ki sun-gun letey hain? In mein se jisne sun-gun li ho woh laaye ko khuli daleel" },
    { number: 39, arabic: "أَمْ لَهُ ٱلْبَنَٰتُ وَلَكُمُ ٱلْبَنُونَ", transliteration: "Am lahu albanatu walakumu albanoona", transliterationB: "Am lahul banaatu wa lakumul banoon", english: "Or has He only daughters and ye have sons", romanUrdu: "Kya Allah ke liye to hain betiyan aur tum logon ke liye hain betay (sons)" },
    { number: 40, arabic: "أَمْ تَسْـَٔلُهُمْ أَجْرًۭا فَهُم مِّن مَّغْرَمٍۢ مُّثْقَلُونَ", transliteration: "Am tasaluhum ajran fahum min maghramin muthqaloona", transliterationB: "Am tas'aluhum ajran fahum mim maghramim musqaloon", english: "Or is it that thou dost ask for a reward, so that they are burdened with a load of debt", romanUrdu: "Kya tum insey koi ajar maangte ho key eh zabardasti padi hui chatti ke bojh taley dabey jatey hain (burdened with a load of debt)" },
    { number: 41, arabic: "أَمْ عِندَهُمُ ٱلْغَيْبُ فَهُمْ يَكْتُبُونَ", transliteration: "Am AAindahumu alghaybu fahum yaktuboona", transliterationB: "Am 'indahumul ghaibu fahum yaktuboon", english: "Or that the Unseen in it their hands, and they write it down", romanUrdu: "Kya inke paas gaib ke haqaiq ka ilm hai ke uski bina par yeh likh rahe hoon" },
    { number: 42, arabic: "أَمْ يُرِيدُونَ كَيْدًۭا ۖ فَٱلَّذِينَ كَفَرُوا۟ هُمُ ٱلْمَكِيدُونَ", transliteration: "Am yureedoona kaydan faallatheena kafaroo humu almakeedoona", transliterationB: "Am yureedoona kaidan fallazeena kafaroo humul makeedoon", english: "Or do they intend a plot (against thee)? But those who defy Allah are themselves involved in a Plot", romanUrdu: "Kya yeh koi chaal chalna chahte hain? (agar yeh baat hai) to kufr karne walon par in ki chaal ulti hi padegi" },
    { number: 43, arabic: "أَمْ لَهُمْ إِلَٰهٌ غَيْرُ ٱللَّهِ ۚ سُبْحَٰنَ ٱللَّهِ عَمَّا يُشْرِكُونَ", transliteration: "Am lahum ilahun ghayru Allahi subhana Allahi AAamma yushrikoona", transliterationB: "Am lahum ilaahun ghairul laa; subhaanal laahi 'ammaa yushrikoon", english: "Or have they a god other than Allah? Exalted is Allah far above the things they associate with Him", romanUrdu: "Kya Allah ke siwa yeh koi aur maabood rakhte hain? Allah paak hai us shirk se jo yeh log kar rahey hain" },
    { number: 44, arabic: "وَإِن يَرَوْا۟ كِسْفًۭا مِّنَ ٱلسَّمَآءِ سَاقِطًۭا يَقُولُوا۟ سَحَابٌۭ مَّرْكُومٌۭ", transliteration: "Wain yaraw kisfan mina alssamai saqitan yaqooloo sahabun markoomun", transliterationB: "Wa iny yaraw kisfam minas samaaa'i saaqitany yaqooloo sahaabum markoom", english: "Were they to see a piece of the sky falling (on them), they would (only) say: \"Clouds gathered in heaps", romanUrdu: "Yeh log aasmaan ke tukde bhi girte huye dekh lein to kahenge yeh baadal hain jo umdey chale aa rahe hain" },
    { number: 45, arabic: "فَذَرْهُمْ حَتَّىٰ يُلَٰقُوا۟ يَوْمَهُمُ ٱلَّذِى فِيهِ يُصْعَقُونَ", transliteration: "Fatharhum hatta yulaqoo yawmahumu allathee feehi yusAAaqoona", transliterationB: "Fazarhum hatta yulaaqoo yawmahumul lazee feehi yus'aqoon", english: "So leave them alone until they encounter that Day of theirs, wherein they shall (perforce) swoon (with terror)", romanUrdu: "Pas aey nabi, inhein inke haal par chodh do yahan tak ke yeh apne us din ko pahunch jayein jismein yeh maar giraye jayenge" },
    { number: 46, arabic: "يَوْمَ لَا يُغْنِى عَنْهُمْ كَيْدُهُمْ شَيْـًۭٔا وَلَا هُمْ يُنصَرُونَ", transliteration: "Yawma la yughnee AAanhum kayduhum shayan wala hum yunsaroona", transliterationB: "Yawma laa yughnee 'anhum kaidumhum shai'anw wa laa hum yunsaroon", english: "The Day when their plotting will avail them nothing and no help shall be given them", romanUrdu: "Jis din na inki apni koi chaal inke kisi kaam aayegi na koi inki madad ko aayega" },
    { number: 47, arabic: "وَإِنَّ لِلَّذِينَ ظَلَمُوا۟ عَذَابًۭا دُونَ ذَٰلِكَ وَلَٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ", transliteration: "Wainna lillatheena thalamoo AAathaban doona thalika walakinna aktharahum la yaAAlamoona", transliterationB: "Wa inna lillazeena zalamoo 'azaaban doona zalika wa laakinna aksarahum laa ya'lamoon", english: "And verily, for those who do wrong, there is another punishment besides this: But most of them understand not", romanUrdu: "Aur us waqt ke aane se pehle bhi zalimon ke liye ek azaab hai, magar in mein se aksar jaante nahin hain" },
    { number: 48, arabic: "وَٱصْبِرْ لِحُكْمِ رَبِّكَ فَإِنَّكَ بِأَعْيُنِنَا ۖ وَسَبِّحْ بِحَمْدِ رَبِّكَ حِينَ تَقُومُ", transliteration: "Waisbir lihukmi rabbika fainnaka biaAAyunina wasabbih bihamdi rabbika heena taqoomu", transliterationB: "Wasbir lihukmi rabbika fa innaka bi-a'yuninaa wa sabbih bihamdi rabbika heena taqoom", english: "Now await in patience the command of thy Lord: for verily thou art in Our eyes: and celebrate the praises of thy Lord the while thou standest forth", romanUrdu: "Aey Nabi , apne Rubb ka faisla aane tak sabr karo. Tum hamari nigaah mein ho. Tum jab utho to apne Rubb ki hamd ke saath uski tasbeeh karo" },
    { number: 49, arabic: "وَمِنَ ٱلَّيْلِ فَسَبِّحْهُ وَإِدْبَٰرَ ٱلنُّجُومِ", transliteration: "Wamina allayli fasabbihhu waidbara alnnujoomi", transliterationB: "Wa minal laili fasabbihhu wa idbaaran nujoom", english: "And for part of the night also praise thou Him,- and at the retreat of the stars", romanUrdu: "Raat ko bhi uski tasbeeh kiya karo aur sitare jab palat-te hain us waqt bhi" }
  ]
};
